import React, { useState, useEffect } from "react";
import { Link } from "react-router-dom";
import axios from "axios";

const Navbar = () => {
  const [showDropdown, setShowDropdown] = useState(false);
  const [categories, setCategories] = useState([]);
  const [loading, setLoading] = useState(true);

  const API_BASE_URL = "http://localhost:5000/api";

  useEffect(() => {
    fetchCategories();
  }, []);

  const fetchCategories = async () => {
    try {
      const response = await axios.get(`${API_BASE_URL}/categories`);
      if (response.data && Array.isArray(response.data)) {
        setCategories(response.data);
      } else {
        setCategories([]);
      }
    } catch (error) {
      console.error("Navbar: Error fetching categories:", error);
      setCategories([]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <nav className="bg-[#fffaf8] text-[#4b2c2b] flex justify-center items-center py-3 px-10 shadow-sm border-t border-[#f0e2da] border-b border-[#f0e2da] relative z-10">
      <div className="flex justify-between items-center w-full max-w-7xl">
        {/* Dropdown danh mục */}
        <div className="relative">
          <button
            onClick={() => setShowDropdown(!showDropdown)}
            className="bg-[#d15574] text-white font-semibold px-5 py-2 rounded-full flex items-center gap-2 hover:bg-[#b74662] transition-all shadow-sm"
          >
            ☰ Danh mục
            <span className="ml-1 text-sm opacity-90">
              {loading ? "..." : `(${categories.length})`}
            </span>
          </button>

          {showDropdown && (
            <div className="absolute top-full left-0 w-72 bg-white shadow-lg rounded-xl mt-3 border border-[#f0e2da] overflow-hidden animate-fadeIn">
              {loading ? (
                <div className="p-4 text-center text-gray-500">
                  <div className="animate-spin rounded-full h-6 w-6 border-t-2 border-b-2 border-[#d15574] mx-auto mb-2"></div>
                  <p>Đang tải danh mục...</p>
                </div>
              ) : categories.length === 0 ? (
                <div className="p-4 text-center">
                  <div className="text-3xl mb-2">📝</div>
                  <p className="font-medium mb-1">Chưa có danh mục nào</p>
                  <Link
                    to="/admin/categories"
                    className="text-[#d15574] font-semibold hover:underline"
                    onClick={() => setShowDropdown(false)}
                  >
                    Thêm danh mục
                  </Link>
                </div>
              ) : (
                <ul className="py-2 max-h-80 overflow-y-auto">
                  {categories.map((category) => (
                    <li
                      key={category._id}
                      className="px-4 py-2 hover:bg-[#fff1f3] text-[#4b2c2b] border-b border-[#f5e6df] last:border-none"
                    >
                      <Link
                        to={`/category/${category.slug}`}
                        onClick={() => setShowDropdown(false)}
                        className="flex justify-between items-center group"
                      >
                        <span className="group-hover:text-[#d15574] transition-colors">
                          {category.name}
                        </span>
                        <span className="text-gray-400 text-xs group-hover:text-[#d15574]">
                          →
                        </span>
                      </Link>
                    </li>
                  ))}
                  <li className="px-4 py-3 border-t border-[#f0e2da] bg-[#fff8f7] text-center">
                    <Link
                      to="/product"
                      className="text-[#d15574] font-bold hover:underline"
                      onClick={() => setShowDropdown(false)}
                    >
                      📦 Xem tất cả sản phẩm
                    </Link>
                  </li>
                </ul>
              )}
            </div>
          )}
        </div>

        {/* Menu chính */}
        <div className="flex gap-10 text-base font-medium">
          {[
            { to: "/", label: "Trang chủ" },
            { to: "/product", label: "Sản phẩm" },
            { to: "/about", label: "Giới thiệu" },
            { to: "/contact", label: "Liên hệ" },
          ].map((item) => (
            <Link
              key={item.to}
              to={item.to}
              className="hover:text-[#d15574] transition-colors duration-200"
            >
              {item.label}
            </Link>
          ))}
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
